    74→	dprintk("%s: call statfs\n", __func__);
    75→	msg.rpc_proc = &nfs_procedures[NFSPROC_STATFS];
    76→	msg.rpc_resp = &fsinfo;
    77→	status = rpc_call_sync(server->client, &msg, 0);
